```typescript
import { ApiResponse, ApiBearerAuth } from '@nestjs/swagger';

@Get(':id')
@ApiBearerAuth('JWT-auth')
@ApiOperation({ summary: 'Récupérer un produit par ID' })
@ApiResponse({ status: 200, description: 'Produit trouvé', type: ProductResponseDto })
@ApiResponse({ status: 401, description: 'Non authentifié - Token JWT manquant ou invalide' })
@ApiResponse({ status: 404, description: 'Produit non trouvé' })
async findOne(@Param('id') id: string) {
  const product = await this.service.findOne(id);
  if (!product) throw new NotFoundException();
  return product;
}
```

