import { ApiQuery } from '@nestjs/swagger';

@Get()
@ApiOperation({ summary: 'Lister les produits avec pagination' })
@ApiQuery({ name: 'page', required: false, type: Number, description: 'Numéro de page', example: 1 })
@ApiQuery({ name: 'limit', required: false, type: Number, description: 'Nombre d\'éléments par page (max 100)', example: 10 })
async findAll(
  @Query('page') page: number = 1,
  @Query('limit') limit: number = 10
) {
  const validLimit = Math.min(limit, 100);
  return this.service.findAll(page, validLimit);
}
