import { ApiProperty } from '@nestjs/swagger';

export class PaginatedResponseDto<T> {
  @ApiProperty({ description: 'Liste des éléments', isArray: true })
  data: T[];

  @ApiProperty({ description: 'Nombre total d\'éléments', example: 42 })
  total: number;

  @ApiProperty({ description: 'Page actuelle', example: 1 })
  page: number;

  @ApiProperty({ description: 'Nombre d\'éléments par page', example: 10 })
  limit: number;

  @ApiProperty({ description: 'Nombre total de pages', example: 5 })
  totalPages: number;
}

// Utilisation dans un contrôleur
@Get()
@ApiOperation({ summary: 'Liste paginée des produits' })
@ApiOkResponse({ type: PaginatedResponseDto })
async findAll(@Query() paginationDto: PaginationDto) {
  const [data, total] = await this.service.findAll(paginationDto);
  return {
    data,
    total,
    page: paginationDto.page,
    limit: paginationDto.limit,
    totalPages: Math.ceil(total / paginationDto.limit),
  };
}
